import java.util.PriorityQueue

fun solve(n: Long, edges: Array<Array<Long>>): Long {
    val numNodes = n.toInt()
    val adj = mutableMapOf<Int, MutableList<Edge>>()

    for (edge in edges) {
        val u = edge[0].toInt()
        val v = edge[1].toInt()
        val start = edge[2]
        val end = edge[3]
        adj.getOrPut(u) { mutableListOf() }.add(Edge(v, start, end))
    }

    val dist = LongArray(numNodes) { Long.MAX_VALUE }
    dist[0] = 0
    val heap = PriorityQueue<Pair<Int, Long>>(compareBy { it.second })
    heap.add(0 to 0L)

    while (heap.isNotEmpty()) {
        val (currentNode, currentTime) = heap.poll()
        if (currentNode == numNodes - 1) {
            return currentTime
        }
        if (currentTime > dist[currentNode]) {
            continue
        }
        for (edge in adj.getOrDefault(currentNode, mutableListOf())) {
            val nextNode = edge.to
            val startTime = edge.start
            val endTime = edge.end
            // The earliest we can take this edge is max(currentTime, startTime)
            val earliestDeparture = maxOf(currentTime, startTime)
            if (earliestDeparture <= endTime) {
                val arrivalTime = earliestDeparture + 1
                if (arrivalTime < dist[nextNode]) {
                    dist[nextNode] = arrivalTime
                    heap.add(nextNode to arrivalTime)
                }
            }
        }
    }

    return -1
}

data class Edge(val to: Int, val start: Long, val end: Long)
